INSERT INTO incidents (id, title, summary, status, severity, source, group_id, primary_asset_id, assignee, created_by, opened_at, mitigated_at, resolved_at, closed_at, root_cause, metadata, created_at, updated_at) VALUES
    ('inc-nas-storage', 'NAS Storage Pool Critical — 91% Capacity', 'ZFS pool ''tank'' on truenas-scale has been trending upward for 7 days, crossing 90% threshold 18 hours ago. Current usage 91.3%. Snapshot retention reduced from 30d to 14d, reclaimed 2.1TB. Monitoring for stabilization before ordering expansion drives.', 'open', 'critical', 'alert_auto', 'grp-storage', 'asset-truenas', 'admin', 'system', '2026-04-15 11:31:00+00', NULL, NULL, NULL, '', '{}'::jsonb, '2026-04-15 11:31:00+00', '2026-04-16 05:31:00+00')
INSERT INTO incidents (id, title, summary, status, severity, source, group_id, primary_asset_id, assignee, created_by, opened_at, mitigated_at, resolved_at, closed_at, root_cause, metadata, created_at, updated_at) VALUES
    ('inc-container-storm', 'Docker Container Restart Storm — Image Pull Failure', 'Bad image tag in docker-compose caused cascading container restarts on docker-prod. 14 of 22 containers entered restart loops. Root cause: registry.example.com rate-limited pulls. Fixed by pinning image digests and adding pull-through cache.', 'resolved', 'high', 'alert_auto', 'grp-services', 'asset-docker', 'admin', 'system', '2026-04-13 05:31:00+00', '2026-04-13 06:31:00+00', '2026-04-13 09:31:00+00', NULL, 'Container registry rate limit caused image pull failures during scheduled update. Compose restart policy cascaded failures across dependent containers.', '{}'::jsonb, '2026-04-13 05:31:00+00', '2026-04-13 09:31:00+00')
INSERT INTO incidents (id, title, summary, status, severity, source, group_id, primary_asset_id, assignee, created_by, opened_at, mitigated_at, resolved_at, closed_at, root_cause, metadata, created_at, updated_at) VALUES
    ('inc-network-outage', 'Network Outage — OPNsense Firmware Update Failure', 'OPNsense firmware update from 24.1 to 24.7 caused kernel panic on reboot. All LAN traffic interrupted for 45 minutes. Recovered by booting previous kernel from console. Firmware update rescheduled with maintenance window.', 'resolved', 'critical', 'manual', 'grp-network', 'asset-opnsense', 'admin', 'admin', '2026-04-11 05:31:00+00', '2026-04-11 06:16:00+00', '2026-04-11 07:31:00+00', NULL, 'OPNsense 24.7 firmware incompatible with Realtek NIC driver. Kernel panic on boot. Upstream bug confirmed in OPNsense forums.', '{}'::jsonb, '2026-04-11 05:31:00+00', '2026-04-11 07:31:00+00')
INSERT INTO incidents (id, title, summary, status, severity, source, group_id, primary_asset_id, assignee, created_by, opened_at, mitigated_at, resolved_at, closed_at, root_cause, metadata, created_at, updated_at) VALUES
    ('inc-k3s-crash', 'K3s cert-manager Webhook CrashLoopBackOff', 'cert-manager-webhook pod entering CrashLoopBackOff after Helm chart upgrade. TLS certificate renewal for ingress resources blocked. Investigating compatibility between cert-manager v1.16 and K3s v1.31.', 'investigating', 'medium', 'alert_auto', 'grp-services', 'asset-k3s-m', 'admin', 'system', '2026-04-16 03:31:00+00', NULL, NULL, NULL, '', '{}'::jsonb, '2026-04-16 03:31:00+00', '2026-04-16 05:31:00+00')
INSERT INTO incidents (id, title, summary, status, severity, source, group_id, primary_asset_id, assignee, created_by, opened_at, mitigated_at, resolved_at, closed_at, root_cause, metadata, created_at, updated_at) VALUES
    ('inc-dev-offline', 'Dev Workstation Unreachable — CI/CD Impact', 'dev-workstation went offline 3 hours ago. Last heartbeat showed elevated disk I/O. GitLab CI jobs using this runner are queuing. Other runners absorbing load but pipeline times increased 3x.', 'open', 'high', 'alert_auto', 'grp-dev', 'asset-dev-ws', '', 'system', '2026-04-16 02:31:00+00', NULL, NULL, NULL, '', '{}'::jsonb, '2026-04-16 02:31:00+00', '2026-04-16 05:31:00+00')
